import { useCallback, useEffect, useRef, useState } from 'react';
import { createArrowNav, type ArrowNavOptions, type ArrowNav } from '@arvo/core';

export interface UseKeyboardNavReturn {
  handleKeyDown: (event: React.KeyboardEvent) => void;
  activeIndex: number;
}

export function useKeyboardNav(
  containerRef: React.RefObject<HTMLElement | null>,
  options: ArrowNavOptions,
): UseKeyboardNavReturn {
  const [activeIndex, setActiveIndex] = useState(0);

  // Refs for mutable values that should not recreate the nav instance.
  const navRef = useRef<ArrowNav | null>(null);
  const onNavigateRef = useRef(options.onNavigate);
  const onSelectRef = useRef(options.onSelect);
  const onEscapeRef = useRef(options.onEscape);

  // Keep callback refs current on every render.
  onNavigateRef.current = options.onNavigate;
  onSelectRef.current = options.onSelect;
  onEscapeRef.current = options.onEscape;

  // Create the nav once; recreate when structural options change.
  useEffect(() => {
    const nav = createArrowNav({
      items: options.items,
      orientation: options.orientation,
      wrap: options.wrap,
      onNavigate(item: HTMLElement, index: number) {
        setActiveIndex(index);
        onNavigateRef.current(item, index);
      },
      onSelect(item: HTMLElement, index: number) {
        onSelectRef.current?.(item, index);
      },
      onEscape() {
        onEscapeRef.current?.();
      },
    });
    navRef.current = nav;
    return () => nav.destroy();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [options.orientation, options.wrap]);

  // Sync items list whenever it changes without recreating the nav.
  useEffect(() => {
    navRef.current?.setItems(options.items);
  }, [options.items]);

  const handleKeyDown = useCallback((event: React.KeyboardEvent) => {
    navRef.current?.handleKeyDown(event.nativeEvent);
  }, []);

  return { handleKeyDown, activeIndex };
}
